-- ── Gramps Web ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open source web app for collaboratively browsing, editing and sharing genealogical family tree data, built on the Gramps desktop database engine.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (self-hosted; optional paid third-party hosting)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Gramps Web Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Gramps Web review covering collaborative family tree editing, self-hosted genealogy hosting, privacy controls, pricing and top alternatives in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Gramps Web is a browser-based and mobile-friendly companion to Gramps, the long-running open source genealogy desktop application, letting multiple family members research and edit a single shared family tree from any device through a JSON REST API and a Progressive Web App front end. The wider Gramps project traces back to April 21, 2001, when Don Allingham shared a personal hobby project he had built as a GEDCOM editor to research his own father's genealogy; his father reportedly suggested the name 'Gramps,' which the community later reverse-engineered into the backronym Genealogical Research and Analysis Management Programming System. The first stable Gramps desktop release arrived on February 11, 2004, after several years of gestation, and the desktop application remains actively developed more than two decades later. Gramps Web itself emerged considerably later as a separate sub-project, developed primarily by contributor David Straub, who began public work on a browser-based front end (initially referred to as gramps-webapp) around 2020 before it matured into the dedicated Gramps Web project with its own site at grampsweb.org and its own GitHub organization repository. Gramps Web has no company or venture funding behind it. It is maintained entirely as a community open source effort under the umbrella of the broader Gramps Project, and both the web app and its REST API are licensed under the GNU Affero General Public License version 3, which requires that any hosted, modified version of the software also make its source code available to users, a meaningfully stronger copyleft position than the desktop application's older licensing. Technically, Gramps Web pairs a Python-based REST API backend with a Progressive Web App frontend, and it is designed for full interoperability with the existing Gramps data model: family trees can move bidirectionally between the desktop application and the web app using the Gramps Web Sync add-on, and the software supports Gramps XML and GEDCOM import and export so users are never locked into the platform. Deployment is Docker-first, with Docker Compose being the recommended and most convenient self-hosting path; images are published for both standard x86-64 servers and ARM architectures, meaning the entire stack can run on a low-cost device like a Raspberry Pi, and a DigitalOcean one-click app is also available for users who prefer a managed cloud VM without a full custom setup. Core features include interactive ancestor, descendant, fan and hourglass family tree chart visualizations; place-mapping tools that plot family history events and residences on interactive maps, including support for custom historical map overlays; record-level privacy controls that let an owner mark data private and control exactly which collaborators can see it, with private records filtered out at the database query layer rather than merely hidden in the interface, for stronger protection of sensitive information about living relatives; the ability to generate most of the same PDF reports the Gramps desktop app supports, including relationship graphs and book-style reports, directly from the browser; a lightweight blogging feature for turning research into narrative family history stories with embedded photos; full data export so users can download their tree data, media files and user accounts at any time for backup or migration to a different server; and a user interface translated by the community into roughly 40 languages. Because the underlying software is entirely free, the only recurring cost most users face is hosting. Users comfortable with Docker can self-host at effectively no cost beyond their own server, while those who prefer a managed option can pay a third-party provider such as Grampshub, run by one of the Gramps Web project's core contributors, to handle infrastructure, backups and updates. This free, self-hostable, data-portable model makes Gramps Web particularly attractive to genealogy hobbyists, extended families and local history societies who want an Ancestry.com- or MyHeritage-style collaborative research experience without recurring subscription fees or being locked into a proprietary data format, trading away the automated historical-record hint matching those commercial services offer in exchange for full data ownership, strong privacy controls and deep interoperability with the mature, two-decade-old Gramps desktop ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b34c93e2-f29b-45a6-8b23-284d2b2cdca9';

