-- ── GraphHopper ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open source routing engine and commercial Directions API providing turn-by-turn navigation, route optimization, isochrones and map matching on OpenStreetMap data.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (500 credits/day, non-commercial use)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Munich, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$GraphHopper Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$GraphHopper review covering the open source routing engine, Directions API, route optimization pricing tiers and top alternatives for developers in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$GraphHopper is a fast, memory-efficient routing engine built on OpenStreetMap data, available both as a free open source Java library or standalone server and as a commercial hosted Directions API offering routing, matrix, isochrone, map matching and route optimization endpoints for cars, trucks, bicycles and pedestrians. The open source GraphHopper project began in 2014, and in January 2016 its developers, together with the team behind the vehicle-routing optimization library jsprit, formally incorporated GraphHopper GmbH in Munich, Germany, to commercialize the underlying technology as a hosted API and to offer enterprise support and licensing to businesses. Company leadership includes Peter Karich, Stefan Schroder and Michael Zilske. GraphHopper GmbH remains an independent, bootstrapped German company rather than a venture-backed startup. Public sources describe a small team of around four employees working remotely from different cities and countries, and there is no public record of institutional funding rounds; the business is instead sustained by paid API subscriptions and enterprise licensing built on top of its two open source projects, which together have accumulated over 6,000 GitHub stars. On the technical side, the core routing engine is released under the Apache License 2.0 and written in Java, and it can run either embedded as a library inside another Java application or as a standalone web server. It builds a routing graph directly from OpenStreetMap data and applies contraction hierarchies and other speedup techniques to calculate routes quickly even across continent-scale road networks. The engine supports configurable vehicle profiles for cars, trucks, bikes and pedestrians, plus a 'custom models' feature that lets developers tune routing costs, for example to avoid tolls or unpaved roads, entirely through configuration rather than by forking and modifying the underlying code. The commercial Directions API bundles several distinct endpoints built on that same engine: a Routing API for point-to-point and turn-by-turn navigation, a Matrix API for calculating many-to-many travel times and distances at once, an Isochrone API for generating reachability polygons showing how far someone can travel within a given time, and a Map Matching API for snapping noisy GPS trace data onto the actual road network. A separately priced Route Optimization API, built on the jsprit vehicle-routing-problem solver, targets last-mile delivery and fleet dispatch use cases where multiple vehicles need efficient multi-stop routes. All of these APIs share the same underlying OpenStreetMap-based routing graph and offer global coverage. Pricing follows a freemium, credit-based model. The Free tier provides 500 credits per day but is capped at five locations per request and restricted to non-commercial use only. Paid tiers scale up from there: Basic at 69 euros per month (5,000 daily credits, up to 30 locations and 2 vehicles per request), Standard at 199 euros per month (15,000 daily credits, up to 80 locations and 10 vehicles), and Premium at 479 euros per month (50,000 daily credits, up to 200 locations and 20 vehicles, with phone support). A custom Enterprise tier offers bulk discount pricing for very high-volume needs, supporting up to 10,000 locations or 200 vehicles per request with dedicated support. All paid tiers include a white-label option and email support with SLA guarantees. This pricing structure, combined with the option to self-host the open source engine entirely for free, positions GraphHopper as a notably lower-cost, open-source-friendly alternative to Google Maps Platform, Mapbox and HERE Technologies for developers who need routing, isochrone and fleet optimization capabilities without the pricing complexity or vendor lock-in of the larger commercial mapping platforms. It is particularly popular among logistics, last-mile delivery, mobility and field-service companies that value both cost predictability and the ability to fall back on self-hosting the engine if they ever need to.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a06850cf-38ac-4eb8-ba1c-a0710d10ee23';

