-- ── Grav ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open source flat-file PHP CMS with no database requirement, offering Git-friendly Markdown content, a modern admin panel and an extensive plugin ecosystem.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (free core; paid premium themes and plugins)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Grav Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Grav review covering the open source flat-file PHP CMS, admin panel, plugin ecosystem, premium themes pricing and top alternatives in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Grav is an open source content management system built in PHP that stores all content and configuration as plain text and Markdown files instead of relying on a database, aiming to combine the simplicity and portability of a static site generator with the dynamic, on-demand rendering and convenient admin interface of a traditional CMS like WordPress. Grav was created by Andy Miller, a co-founder of the Joomla project and founder of the premium theme studio RocketTheme, who set out to build a free, open source flat-file CMS with all the polish of a commercial product but without any licensing cost to end users. The project was first released in 2014 and reached its 1.0 stable milestone on November 12, 2015, after roughly a year and a half of open development, with RocketTheme serving as its first, and for many years primary, premium theme provider. Grav has no outside venture investors. It is developed and commercially supported by Trilby Media LLC, Andy Miller's company and the successor entity behind RocketTheme, which monetizes the free core CMS by selling premium themes, plugins and support bundles directly on the Grav website rather than through a subscription SaaS model. The underlying software itself remains permanently free and is released under the permissive MIT License. On the technical side, Grav 2.x is built on a modern PHP 8.3 and above foundation using the Symfony 7 framework and Twig 3 templating engine. Content lives as folders of Markdown files with YAML frontmatter, which can be version-controlled directly in Git and copied between servers without any database export or migration step, making a Grav site fully portable by design. The platform ships a first-party REST API that powers both its Admin 2.0 single-page-application interface, built with SvelteKit 5, Vite and Tailwind CSS for near-instant page navigation, a customizable dashboard and real-time collaborative editing, and headless integrations for developers who want to consume Grav's content from a separate front end. A newer addition is a Model Context Protocol server that lets AI agents interact with the CMS using the same permission model and API surface available to human administrators. Core features beyond the flat-file architecture include the Grav Package Manager, referred to as GPM, and a built-in command-line console for installing and updating themes and plugins without touching the file system manually; a Debug Bar for development diagnostics; built-in multi-language support for internationalized sites; an automatic image optimization pipeline that handles resizing, cropping and format conversion; full-text search, with a paid 'YetiSearch Pro' upgrade available for production-scale search needs; and an extensive plugin and theme marketplace covering use cases from blogs and portfolios to documentation sites. Pricing follows a classic open-core model. The Grav core CMS, its Admin 2.0 panel and the GPM package manager are entirely free to download and self-host, with no limit on the number of sites a user can run. Revenue for Trilby Media comes from optional premium products sold on top of that free core, such as individual premium themes, for example the Helios theme priced around 50 dollars, and larger bundled packages combining documentation-focused themes, editors and search tooling priced around 200 dollars, each sold with lifetime updates and support included. This structure makes Grav attractive to developers and agencies who want WordPress-like editing convenience without the operational overhead of installing, securing and migrating a MySQL database, and it is often chosen specifically for its Git-native workflow. Competitively, Grav positions itself as a developer-centric middle ground between traditional database-backed content management systems like WordPress and Joomla on one side, and pure static site generators like Jekyll and Hugo on the other: it offers dynamic, on-demand page rendering and a polished admin interface, but with none of the database management burden that comes with the larger, more established CMS platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fbbd32cd-6120-4478-b00a-9de654f9e59e';

