INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Unified Dashboards$q$, $q$Build dashboards that mix metrics, logs and traces from multiple systems in one visual pane with template variables and 30+ panel types.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$150+ Data Source Connectors$q$, $q$Native plugins for Prometheus, Loki, Tempo, Elasticsearch, CloudWatch, Azure Monitor, Google Cloud Monitoring and many more.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Unified Alerting$q$, $q$Multi-dimensional alert rules that route notifications to Slack, PagerDuty, email or Grafana OnCall.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Explore Mode$q$, $q$Ad hoc, code-free querying across metrics, logs and traces without building a full dashboard first.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Grafana OnCall$q$, $q$Incident escalation and on-call scheduling built directly into the Grafana ecosystem.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Synthetic Monitoring and k6$q$, $q$Uptime checks and load testing tools, including the k6 project acquired by Grafana Labs in 2021.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Grafana Machine Learning and Assistant$q$, $q$AI-driven anomaly detection plus a natural-language assistant for generating dashboards and queries.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Enterprise Plugins and RBAC$q$, $q$SSO, fine-grained role-based access control and premium connectors for tools like Splunk and ServiceNow.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Free and open source core with no vendor lock-in to a single data store$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Connects to virtually any metrics, logs or trace data source in one interface$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Highly customizable dashboards backed by a large community plugin ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Usage-based Cloud pricing can be more cost-effective at scale than closed observability suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Usage-based Cloud pricing can become unpredictable for high-cardinality metrics$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Self-hosting the full LGTM stack requires meaningful operational expertise$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Some advanced features like SSO and premium connectors require Enterprise licensing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$PromQL, LogQL and TraceQL have a learning curve for newcomers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Is Grafana free to use?$q$, $q$Yes. The open source core is free to self-host, and Grafana Cloud also offers a free tier with 10,000 metric series and 50 GB of logs, traces and profiles per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$What is the difference between Grafana and Grafana Cloud?$q$, $q$Grafana is the self-hosted open source software; Grafana Cloud is Grafana Labs' fully managed hosting service built around the same software plus the LGTM stack.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Does Grafana store data itself?$q$, $q$No. Grafana is primarily a visualization and alerting layer that queries external data sources like Prometheus, Loki or Elasticsearch rather than owning the underlying data.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$What is the LGTM stack?$q$, $q$LGTM stands for Loki (logs), Grafana (visualization), Tempo (traces) and Mimir (metrics), Grafana Labs' complementary open source observability projects.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Can Grafana replace Datadog or New Relic?$q$, $q$Many teams use Grafana paired with Prometheus, Loki and Tempo as a lower-cost, vendor-neutral alternative to closed observability suites like Datadog and New Relic.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$What license does Grafana use?$q$, $q$Grafana's core code has been licensed under AGPLv3 since 2021, after previously being licensed under Apache 2.0.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Infrastructure and Kubernetes Monitoring$q$, $q$Visualize cluster health, resource usage and application metrics collected by Prometheus and other exporters.$q$, $q$DevOps and SRE teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Business and Executive Reporting Dashboards$q$, $q$Combine data from SQL databases, APIs and cloud services into shareable business dashboards.$q$, $q$Product and business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$IoT and Sensor Data Visualization$q$, $q$Monitor time-series data streaming from industrial sensors, devices and edge deployments.$q$, $q$Engineering and industrial teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited dashboards","Connect to any supported data source","Community plugin ecosystem","Self-managed infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Cloud Free$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["10,000 active metric series","50 GB logs, traces and profiles per month","3 active visualization users","14-day retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Cloud Pro$q$, $q$From $19/month plus usage$q$, $q$Monthly$q$, NULL, $q$["$6.50 per 1,000 active series","~$0.45 per GB of logs, traces and profiles","$8 per active user"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Cloud Advanced$q$, $q$From $55/month$q$, $q$Monthly$q$, NULL, $q$["Higher included data volumes","Longer retention windows","Access to advanced enterprise plugins"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$Enterprise$q$, $q$Custom (from around $25,000/year)$q$, $q$Annual$q$, NULL, $q$["Dedicated support","Compliance and security controls","Self-managed or cloud deployment options"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grafana began life in 2012 as a Kibana fork built by Torkel Odegaard specifically for visualizing time-series metrics, and it became the company Grafana Labs (originally Raintank) in 2014. Today it is best known as the open source visualization and alerting layer that sits on top of metrics, logs and trace data wherever that data already lives, rather than requiring teams to migrate into a proprietary data store.$q$, $q$The company has grown into a fully remote-first organization with roughly 1,800 employees across more than 50 countries, and it has raised about 1.09 billion dollars in venture funding, reaching unicorn status in 2021 at a 6 billion dollar valuation with backers including Sequoia Capital, Coatue and GIC.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Grafana connects to more than 150 data sources through its plugin architecture, including Prometheus, Loki, Tempo, Elasticsearch and every major cloud provider's native monitoring service, letting teams build unified dashboards that mix metrics, logs and traces in a single pane.$q$, $q$Beyond dashboards, the platform includes unified alerting, an ad hoc Explore query mode, Grafana OnCall for incident escalation, Synthetic Monitoring, k6 load testing, and newer AI-assisted features like anomaly detection and natural-language dashboard generation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The open source core is free to self-host under the AGPLv3 license. Grafana Cloud adds a managed hosting option starting with a generous free tier covering 10,000 active metric series and 50 GB each of logs, traces and profiles per month with 14-day retention.$q$, $q$Paid Cloud tiers run from a Pro plan at roughly 19 dollars per month plus usage, through an Advanced tier around 55 dollars per month, up to custom Enterprise contracts that typically start near a 25,000 dollar annual commitment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
