INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1a437a0b-2569-49db-aa44-9626350f97d5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Real-Time Grammar and Spell Check$q$, $q$Inline correction of grammar, spelling and punctuation as you type across supported apps and websites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Tone Detector$q$, $q$Flags how a message is likely to read to its recipient before it is sent.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$AI Writing Assistant$q$, $q$Generative AI that can draft, rewrite, summarize or brainstorm text from a prompt.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Plagiarism and AI-Content Checker$q$, $q$Scans text against billions of web pages and academic sources and flags likely AI-generated content.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Full-Sentence Rewrites$q$, $q$Suggests complete sentence-level rewrites rather than just word-level fixes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Cross-Platform Integrations$q$, $q$Browser extensions, desktop apps for Windows and Mac, a mobile keyboard, and Microsoft Office/Google Docs add-ins.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Team Style Guides and Brand Tones$q$, $q$Custom rules and preferred terminology so teams write with a consistent brand voice.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Admin Analytics$q$, $q$Reporting for Pro and Enterprise admins to track writing quality and adoption across an organization.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Works inline across hundreds of thousands of websites and applications via browser extension$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Free tier is genuinely useful for basic grammar and spelling correction$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Tone detection helps avoid miscommunication in professional writing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Strong plagiarism and AI-content detection tools for academic and content use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Full feature set, including rewrites and plagiarism checking, requires the paid Pro plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Monthly AI prompt limits on Free and Pro plans can be restrictive for heavy users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Primarily optimized for English, with limited support for other languages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Browser extension can occasionally conflict with other web apps or affect page performance$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Is Grammarly free?$q$, $q$Yes, Grammarly offers a Free tier with basic grammar and spelling correction and 100 AI prompts per month; advanced features require Pro or Enterprise.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$What is Grammarly Pro?$q$, $q$Grammarly Pro is the current paid plan that replaced the former separate Premium and Business plans, supporting individuals and teams of up to 149 seats.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Does Grammarly work in Google Docs and Microsoft Word?$q$, $q$Yes, Grammarly offers dedicated add-ins for Google Docs and Microsoft Office alongside its browser extension and desktop apps.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Can Grammarly detect AI-generated text?$q$, $q$Yes, Grammarly includes an AI-generated-text detector alongside its traditional plagiarism checker.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Is Grammarly safe for confidential documents?$q$, $q$Grammarly Enterprise offers additional controls like bring-your-own-key encryption and data loss prevention for sensitive content; check the current privacy policy for individual plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Who owns Grammarly?$q$, $q$Grammarly is a private company backed by investors including General Catalyst, BlackRock and Baillie Gifford, last valued around 13 billion dollars.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Academic Writing and Plagiarism Checking$q$, $q$Check essays and research papers for grammar issues and unintentional plagiarism.$q$, $q$Students and researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Business Email and Professional Communication$q$, $q$Catch tone and clarity issues in outbound emails and customer messages before sending.$q$, $q$Sales, support and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Content Marketing and Editorial Workflows$q$, $q$Standardize grammar, style and brand voice across a content team's output.$q$, $q$Content teams and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Basic grammar and spelling correction","Tone detection","100 AI prompts per month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Pro$q$, $q$$12/month (billed annually) or up to $30/month (billed monthly)$q$, $q$Monthly or Annual$q$, NULL, $q$["Full-sentence rewrites","Plagiarism and AI-content detection","Unlimited personalized suggestions","2,000 AI prompts per member per month","Up to 149 seats"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["SSO and SCIM","Data loss prevention","Bring-your-own-key encryption","Unlimited AI prompts per member","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grammarly was founded in 2009 by Alex Shevchenko, Max Lytvyn and Dmytro Lider, evolving from earlier plagiarism-detection work into the browser-based grammar and writing assistant used by hundreds of millions of people today. The company is headquartered in San Francisco and has raised roughly 545 million dollars in disclosed venture funding at a peak valuation around 13 billion dollars, plus a further 1 billion dollar growth round in 2025.$q$, $q$That 2025 round accompanied acquisitions of the productivity tool Coda and the Superhuman email client, marking Grammarly's shift from a single-purpose grammar checker toward a broader AI productivity platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Grammarly combines rule-based grammar and spelling correction with large-language-model-powered generative writing tools, delivered inline through browser extensions, desktop apps, a mobile keyboard, and Microsoft Office and Google Docs integrations covering roughly 500,000 apps and websites.$q$, $q$Beyond basic corrections, it offers tone detection, full-sentence rewrites, a plagiarism and AI-content detector, and team-focused style guides and analytics for organizations standardizing writing quality across staff.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Grammarly's Free tier covers basic grammar and spelling correction plus 100 AI prompts per month. Grammarly Pro, which now replaces the former separate Premium and Business plans, costs about 12 dollars per month billed annually and supports up to 149 seats.$q$, $q$Larger organizations move to a custom-priced Enterprise plan that adds SSO, SCIM, data loss prevention, bring-your-own-key encryption and unlimited AI prompts per member.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8069bad0-6be8-4d8e-bbf8-5cdf38829228', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
