INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Interactive Family Tree Charts$q$, $q$Explore ancestor, descendant, fan and hourglass chart visualizations of a family tree.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Collaborative Multi-User Editing$q$, $q$Multiple family members can research and edit a shared tree from any browser or device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Historical Map Overlays$q$, $q$Plot family history events and places on interactive maps with custom historical overlays.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Privacy-Aware Record Permissions$q$, $q$Private records are filtered out at the database layer, not just hidden in the UI, for stronger data protection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Gramps Desktop Sync$q$, $q$Bidirectional synchronization with the Gramps desktop app via the Gramps Web Sync add-on.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Full Data Export$q$, $q$Download all tree data, media files and user accounts at any time for backup or migration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$In-Browser Report Generation$q$, $q$Generate PDF relationship graphs and book-style reports without leaving the browser.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Self-Hosted Docker Deployment$q$, $q$Runs via Docker Compose on standard servers or ARM devices like a Raspberry Pi.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Completely free and open source with no required subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Full interoperability with the mature, two-decade-old Gramps desktop application$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Strong, database-level privacy controls, well suited to sensitive living-relative data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Self-hostable, giving users complete ownership of their genealogical data$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Requires comfort with Docker or a paid host like Grampshub for non-technical users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Lacks the automated historical record hints and document matching of commercial services like Ancestry$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Smaller community and slower feature development pace than venture-backed competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$No dedicated native mobile app; relies on the mobile web experience$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Is Gramps Web free?$q$, $q$Yes, Gramps Web is free and open source under the AGPL-3.0 license; the only potential cost is hosting if you choose a managed provider.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$What is the difference between Gramps and Gramps Web?$q$, $q$Gramps is the original desktop genealogy application; Gramps Web is a browser-based, multi-user collaborative front end built on the same underlying data model.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Can I sync Gramps Web with the Gramps desktop app?$q$, $q$Yes, using the Gramps Web Sync add-on, data can be synchronized bidirectionally between the desktop app and Gramps Web.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Does Gramps Web support automated record hints like Ancestry?$q$, $q$No, it is a family tree management and collaboration tool rather than a historical-record matching service.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Can I self-host Gramps Web?$q$, $q$Yes, the recommended method is Docker Compose, and it also supports ARM devices such as a Raspberry Pi.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$What license is Gramps Web released under?$q$, $q$Gramps Web and its API are licensed under the GNU Affero General Public License version 3 (AGPL-3.0).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Collaborative Family History Research$q$, $q$Let extended family members contribute to and edit a shared family tree together.$q$, $q$Extended families researching together$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Genealogy Society Record Keeping$q$, $q$Maintain and share community genealogical records with controlled access.$q$, $q$Local history and genealogy societies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Privacy-Conscious Family Tree Hosting$q$, $q$Keep sensitive data about living relatives fully under the family's control.$q$, $q$Users wanting full data ownership$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Self-Hosted (Community)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full feature set","Self-managed Docker hosting","Unlimited users and trees limited only by server resources"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$Managed Hosting (e.g. Grampshub)$q$, $q$Varies by provider$q$, $q$Monthly or Annual$q$, NULL, $q$["Managed infrastructure","Backups and updates handled by the host","No server maintenance required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gramps Web is the collaborative, browser-based counterpart to Gramps, an open source genealogy desktop application that Don Allingham started as a personal hobby project in 2001. Gramps Web itself was developed later, led primarily by contributor David Straub, emerging as a public project around 2020.$q$, $q$It has no company or investors behind it and is maintained as a community open source project licensed under the AGPL-3.0, which requires hosted derivatives of the software to also share their source code.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gramps Web offers interactive ancestor, descendant, fan and hourglass family tree charts, historical map overlays, and record-level privacy controls that filter private data at the database layer so sensitive information about living relatives stays protected.$q$, $q$It syncs bidirectionally with the Gramps desktop app, generates the same PDF reports the desktop version supports, and lets users export all of their data at any time, avoiding vendor lock-in entirely.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The software itself is completely free and open source. Users who are comfortable with Docker can self-host at no software cost, including on low-cost hardware like a Raspberry Pi.$q$, $q$Those who prefer not to manage a server can pay a third-party host such as Grampshub, run by a core Gramps Web contributor, for managed hosting, backups and updates.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b34c93e2-f29b-45a6-8b23-284d2b2cdca9', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Multi-Store and Multi-Tenant Architecture$q$, $q$Run several storefronts or independent merchant tenants from a single GrandNode installation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Multi-Vendor Marketplace Support$q$, $q$Built-in tools for hosting and managing third-party sellers on a marketplace storefront.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$B2B and B2C Commerce in One Platform$q$, $q$Supports customer-specific wholesale pricing alongside standard consumer checkout flows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Headless, API-First Storefront$q$, $q$Swap the default storefront for a custom React, Vue or Next.js front end while keeping the .NET backend.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Multi-Language and Multi-Currency$q$, $q$Native support for serving multiple languages and currencies without extra plugins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$MongoDB-Based Data Layer$q$, $q$Document-oriented storage designed for horizontal scalability compared to relational databases.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Built-In SEO and Promotion Tools$q$, $q$SEO-friendly URLs, metadata controls and discount and promotion engines out of the box.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Docker-Based Deployment$q$, $q$Containerized deployment on AWS, Azure or self-managed infrastructure with S3-compatible storage support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Free and fully open source with complete access to the source code$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Native multi-vendor and multi-tenant support without extra plugins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Built on .NET Core and MongoDB, appealing to teams already in the Microsoft stack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Headless architecture allows a fully custom storefront front end$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Smaller theme and plugin ecosystem than Magento or Shopify$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Requires .NET and MongoDB expertise to self-host and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Documentation and community support are thinner than larger open source platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$No official managed cloud hosting directly from GrandNode; relies on partner agencies$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Is GrandNode free?$q$, $q$Yes, GrandNode is free and open source software that you can self-host and modify.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$What database does GrandNode use?$q$, $q$GrandNode uses MongoDB by default, with support for AWS DocumentDB and Azure CosmosDB as alternatives.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Can GrandNode support a marketplace with multiple vendors?$q$, $q$Yes, multi-vendor marketplace functionality is built into the platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Is GrandNode headless?$q$, $q$Yes, it offers an API-first design that allows the default storefront to be replaced with a custom frontend.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Who maintains GrandNode?$q$, $q$GrandNode is maintained by a small development team based in Krakow, Poland, supported by a network of certified partner agencies.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Does GrandNode offer hosting?$q$, $q$GrandNode itself does not sell managed hosting directly; certified partners offer hosting, implementation and support services.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Multi-Vendor Marketplace Development$q$, $q$Build a marketplace platform where independent sellers list and manage their own products.$q$, $q$Agencies building marketplace platforms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$B2B Wholesale Storefronts$q$, $q$Serve wholesale buyers with customer-specific pricing and quote workflows.$q$, $q$.NET development teams serving B2B clients$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Headless Commerce Projects$q$, $q$Pair the GrandNode backend with a custom React or Vue storefront.$q$, $q$Developers building custom storefronts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Community / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Self-hosted deployment","All core commerce features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$Partner Implementation and Support$q$, $q$Custom pricing via certified partners$q$, $q$Project-based or Annual$q$, NULL, $q$["Hosting setup and management","Custom development and customization","Ongoing support services"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GrandNode is an open source e-commerce platform built on ASP.NET Core and MongoDB, started in 2015 by a small team based in Krakow, Poland, who set out to build the first e-commerce platform combining .NET with a MongoDB data layer. The first stable release shipped in January 2016.$q$, $q$The project shares conceptual roots with the ASP.NET platform nopCommerce and documents a migration path from nopCommerce's SQL schema, but it has evolved into an independently maintained platform with its own multi-store, multi-vendor and headless architecture.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GrandNode natively supports multi-store, multi-vendor marketplace and multi-tenant deployments from a single installation, along with built-in multi-language and multi-currency support, without requiring third-party extensions.$q$, $q$Its headless, API-first design lets developers swap the default storefront for a custom React, Vue or Next.js front end while keeping the .NET backend for catalog, order and inventory management, making it well suited to custom commerce builds.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core GrandNode platform is entirely free to download, self-host and modify, with the source code published openly on GitHub.$q$, $q$Revenue for the project comes from a certified partner network offering paid implementation, hosting and support services rather than from a direct subscription fee for the software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d5b3bdc-eff0-48ab-b65b-30a03203b12e', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Drag-and-Drop Visual Canvas$q$, $q$A live editing canvas with a nested component tree for building templates without hardcoding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Framework-Agnostic Component Engine$q$, $q$Use it standalone or wrap it for React, Vue or Angular applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Email-Safe HTML Export Presets$q$, $q$Generates table-based HTML that renders correctly across major email clients.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Style Manager Without Code$q$, $q$Visually adjust CSS properties without writing stylesheets by hand.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Plugin and Command API$q$, $q$Extend the editor with custom blocks, traits and commands.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Embeddable Studio SDK$q$, $q$A packaged, white-labelable version of the editor for embedding in SaaS products.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Multi-Project and Multi-Domain Support$q$, $q$Manage several embedded editor instances across different domains within the Studio SDK.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$AI-Assisted Template Generation$q$, $q$The hosted Studio product can generate pages and templates from natural-language prompts.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Core framework is free, open source and fully self-hostable$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Framework-agnostic, making it easy to embed inside React, Vue or Angular apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Large, mature plugin ecosystem after nearly a decade of development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Studio SDK lets SaaS teams add a page builder without building one from scratch$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Raw GrapesJS requires developer effort to integrate and style into a production-ready editor$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Studio SDK paid tiers can get expensive quickly based on session volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Free open source tier has fewer dedicated support resources than paid SDK customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$The newer AI and hosted Studio features are still early and less battle-tested than the core library$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Is GrapesJS free?$q$, $q$Yes, the core GrapesJS library is free and open source; the commercial Studio SDK adds paid tiers for embeddable, white-labeled use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$What is the GrapesJS Studio SDK?$q$, $q$It is a paid, packaged version of the GrapesJS editor designed to be embedded directly inside SaaS products.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$What is Grapes Studio?$q$, $q$Grapes Studio is a separate hosted, AI-powered website and email builder company founded by GrapesJS creator Artur Arseniev in 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Can GrapesJS build email templates?$q$, $q$Yes, it includes presets that generate email-safe, table-based HTML compatible with major email clients.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Does GrapesJS require React or Vue?$q$, $q$No, it is framework-agnostic and works standalone or wrapped for popular frontend frameworks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Who created GrapesJS?$q$, $q$GrapesJS was created by Italian developer Artur Arseniev, who first released it in 2016.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Embedded Page Builders for SaaS Products$q$, $q$Add a branded drag-and-drop page or template builder to an existing product.$q$, $q$SaaS product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Email Template Editors$q$, $q$Let end users build and customize email-safe HTML templates visually.$q$, $q$Email marketing platforms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Custom CMS and Website Builders$q$, $q$Build bespoke website editing tools for client projects.$q$, $q$Agencies and developers building client tools$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Open Source Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted library","Full source code access","Community plugin ecosystem"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Studio SDK Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["1,000 sessions per month","1 domain","Studio branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Studio SDK Startup$q$, $q$$200/month$q$, $q$Monthly$q$, NULL, $q$["20,000 sessions per month","2 domains","Custom branding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Studio SDK Business$q$, $q$$2,000/month$q$, $q$Monthly$q$, NULL, $q$["50,000 sessions per month","Wildcard domain support","Dedicated Slack channel"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$Studio SDK Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Unlimited sessions","24/7 support","Custom development"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GrapesJS is an open source, framework-agnostic drag-and-drop editor framework created by Artur Arseniev in 2016 to solve the problem of hardcoding email newsletter templates by hand for every client change. It is most commonly embedded inside other software products rather than used as a standalone application.$q$, $q$In 2025 Arseniev co-founded Grapes Studio Inc with Y Combinator alumnus Griffin Kelly, backed by Open Core Ventures, to build a commercial, AI-powered version of the editor, while the underlying GrapesJS open source project remains freely available on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core library offers a drag-and-drop canvas, a visual style manager, and a plugin architecture with presets for email-safe HTML and general webpage building, usable standalone or wrapped for React, Vue or Angular.$q$, $q$The commercial Studio SDK packages the editor as an embeddable, white-labelable component for SaaS products, with multi-project support and, in the hosted Studio app, AI-assisted template generation from prompts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The GrapesJS core library is completely free and open source, with no license fee for self-hosting and integrating it into your own codebase.$q$, $q$The Studio SDK adds paid, session-based tiers starting with a free plan for 1,000 sessions per month, scaling through Startup at 200 dollars per month and Business at 2,000 dollars per month, up to custom Enterprise pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('95c8082d-ffa9-4958-bc60-8f9f554f3f0a', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
