INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Turn-by-Turn Routing API$q$, $q$Point-to-point navigation with turn-by-turn instructions for cars, trucks, bikes and pedestrians.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Matrix API$q$, $q$Calculate many-to-many travel times and distances in a single request.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Isochrone API$q$, $q$Generate reachability polygons showing how far someone can travel within a given time.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Map Matching$q$, $q$Snap noisy GPS trace data onto the actual road network.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Route Optimization API$q$, $q$Vehicle-routing-problem solving for last-mile delivery and fleet dispatch, built on jsprit.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Custom Vehicle Profiles and Models$q$, $q$Tune routing costs for trucks or specialized vehicles through configuration, not code forks.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Self-Hostable Open Source Engine$q$, $q$The core routing engine can run as a Java library or standalone server at no cost.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Global OpenStreetMap Coverage$q$, $q$Routing graphs built directly from OpenStreetMap data worldwide.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Open source core can be self-hosted for free with no per-call fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Significantly cheaper than Google Maps Platform or Mapbox at scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Covers routing, matrix, isochrone, map matching and optimization in one API family$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Fine-grained custom routing profiles for trucks and specialized vehicles$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Free tier is limited to non-commercial use and low request volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Small company size, reportedly around four employees, means limited support bandwidth$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Routing quality depends on OpenStreetMap data coverage, which can vary by region$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Self-hosting the engine requires Java and infrastructure expertise$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Is GraphHopper free?$q$, $q$The open source routing engine is free to self-host, and the hosted Directions API offers a free tier for non-commercial use with 500 credits per day.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$What is the difference between GraphHopper open source and the Directions API?$q$, $q$The open source project is a self-hosted Java library or server; the Directions API is GraphHopper GmbH's fully hosted commercial service built on the same engine.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Does GraphHopper support truck routing?$q$, $q$Yes, through custom vehicle profiles that account for truck-specific restrictions like height, weight and toll avoidance.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$What is the Route Optimization API?$q$, $q$A separately priced endpoint built on the jsprit solver for planning efficient multi-stop routes across a fleet of vehicles.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$What map data does GraphHopper use?$q$, $q$GraphHopper builds its routing graphs from OpenStreetMap data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Who owns GraphHopper?$q$, $q$GraphHopper is owned by the independently held GraphHopper GmbH, headquartered in Munich, Germany.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Last-Mile Delivery Route Optimization$q$, $q$Plan efficient multi-stop delivery routes across a vehicle fleet.$q$, $q$Logistics and delivery companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$In-App Turn-by-Turn Navigation$q$, $q$Embed turn-by-turn directions directly inside a mobility or ride-hailing app.$q$, $q$Mobility and ride-hailing app developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Fleet and Field Service Dispatch$q$, $q$Optimize technician or driver schedules and routes across many daily stops.$q$, $q$Field service and fleet management companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Free$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["500 credits per day","Max 5 locations per request","Non-commercial use only"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Basic$q$, $q$EUR69/month$q$, $q$Monthly$q$, NULL, $q$["5,000 credits per day","Max 30 locations","2 vehicles per request","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Standard$q$, $q$EUR199/month$q$, $q$Monthly$q$, NULL, $q$["15,000 credits per day","Max 80 locations","10 vehicles per request"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Premium$q$, $q$EUR479/month$q$, $q$Monthly$q$, NULL, $q$["50,000 credits per day","Max 200 locations","20 vehicles per request","Phone support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$Custom / Enterprise$q$, $q$Custom pricing$q$, $q$Annual$q$, NULL, $q$["Up to 10,000 locations per request","Up to 200 vehicles per request","Dedicated support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GraphHopper is a routing engine built on OpenStreetMap data, available as a free open source Java library or as a commercial hosted Directions API. The open source project began in 2014, and GraphHopper GmbH was incorporated in Munich, Germany in January 2016 to commercialize it.$q$, $q$The company remains small and independent, reportedly around four employees working remotely, with no public venture funding, sustained instead by paid API subscriptions and enterprise licensing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Directions API bundles a Routing API, a Matrix API for many-to-many travel calculations, an Isochrone API for reachability polygons, and a Map Matching API for snapping GPS traces to roads, all built on the same OpenStreetMap-based graph.$q$, $q$A separately priced Route Optimization API, built on the jsprit vehicle-routing solver, targets last-mile delivery and fleet dispatch, while custom vehicle profiles let developers tune routing for trucks and specialized vehicles.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$A Free tier offers 500 credits per day for non-commercial use, capped at five locations per request. Paid tiers scale from Basic at 69 euros per month through Standard at 199 euros and Premium at 479 euros per month.$q$, $q$A custom Enterprise tier supports up to 10,000 locations or 200 vehicles per request with dedicated support, and the underlying open source engine can also be self-hosted entirely for free.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a06850cf-38ac-4eb8-ba1c-a0710d10ee23', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$DOT Language Graph Description$q$, $q$A simple declarative text syntax for describing nodes, edges, clusters and attributes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Multiple Layout Engines$q$, $q$Includes dot, neato, fdp, sfdp, circo and twopi for hierarchical, force-directed, circular and radial layouts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$40+ Output Formats$q$, $q$Export to SVG, PDF, PNG, JSON and many other raster, vector and structured formats.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Custom Node and Edge Styling$q$, $q$Control colors, fonts, line styles, hyperlinks and HTML-like tabular node labels.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Command-Line Tools and C Library$q$, $q$Use Graphviz as standalone binaries or embed its rendering library in another application.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Language Bindings$q$, $q$Bindings and wrappers for Python, Java, Perl, Ruby and JavaScript, among others.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Clustered and Radial Layouts$q$, $q$Specialized layout tools like osage and patchwork for treemap and clustered structures.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Embeddable in Documentation Pipelines$q$, $q$Commonly used inside tools like Doxygen, Sphinx and CI/CD dependency graph renderers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Completely free, open source and dependency-light$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Extremely mature and stable after more than three decades of development$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Wide output format support makes it easy to embed rendered diagrams anywhere$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Fully scriptable and automatable, ideal for generating diagrams programmatically from code$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Default visual styling looks dated compared to modern interactive visualization tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$No built-in interactivity or drag-and-drop diagram editing by default$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Learning the DOT language and layout engine behavior takes time for complex graphs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Large or dense graphs can produce cluttered layouts without careful manual tuning$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Is Graphviz free?$q$, $q$Yes, Graphviz is fully open source and free to use, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$What is the DOT language?$q$, $q$DOT is the declarative text format Graphviz uses to describe a graph's nodes, edges and attributes.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$What file formats can Graphviz export to?$q$, $q$Graphviz supports more than 40 output formats, including SVG, PDF, PNG and JSON.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Does Graphviz have a graphical editor?$q$, $q$No, Graphviz is primarily a command-line and library-based rendering engine rather than a GUI editor.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Who maintains Graphviz today?$q$, $q$It is maintained largely by volunteer contributors, while ownership of the software remains with AT and T.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Can I use Graphviz from Python or JavaScript?$q$, $q$Yes, community bindings exist for Python, Java, Ruby and JavaScript, among other languages.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Software Architecture and Dependency Diagrams$q$, $q$Automatically generate diagrams of module dependencies, call graphs or class hierarchies.$q$, $q$Software engineers and technical writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Automated Documentation Graph Generation$q$, $q$Embed Graphviz inside documentation tools to render diagrams from code at build time.$q$, $q$Developer tooling and documentation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Bioinformatics and Network Structure Visualization$q$, $q$Visualize complex biological pathways or network topologies from structured data.$q$, $q$Researchers and data scientists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full toolkit with all layout engines","All 40+ output formats","Unlimited use with no license fee"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Graphviz originated at AT and T Bell Labs, with the earliest documented work published in a September 1991 technical report by researchers Eleftherios Koutsofios and Stephen North. It grew out of AT and T's need to automatically lay out large telecommunications network and software call graphs.$q$, $q$The software has no company or investors behind it; it remains owned by AT and T but has been released as free and open source software under the Eclipse Public License, maintained largely by volunteer contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Graphviz parses graphs written in the DOT language and renders them using specialized layout engines, including 'dot' for hierarchical diagrams, 'neato' and 'fdp' for force-directed layouts, and 'circo' and 'twopi' for circular and radial layouts.$q$, $q$It supports more than 40 output formats, from raster images and SVG to PDF and structured JSON, along with rich node and edge styling and language bindings for Python, Java, JavaScript and more.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Graphviz is entirely free and open source software with no pricing tiers, subscriptions or commercial edition.$q$, $q$It is most commonly consumed as an embedded dependency inside other developer tools, such as documentation generators and CI/CD pipelines, rather than purchased or licensed directly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('810dd7ba-142d-43eb-a0cd-c0bc68503b42', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Flat-File, Database-Free Architecture$q$, $q$Content and configuration are stored as plain text and Markdown files instead of a database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Git-Friendly Markdown Content$q$, $q$Version control all content and configuration directly in Git using Markdown files with YAML frontmatter.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Admin 2.0 Dashboard$q$, $q$A SvelteKit-based single-page admin interface with real-time collaborative editing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Grav Package Manager and CLI Console$q$, $q$Install and update themes and plugins from the command line without manual file management.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$First-Party REST API and MCP Server$q$, $q$Headless content access plus a Model Context Protocol server for AI agent integration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Built-In Multi-Language Support$q$, $q$Native internationalization for building multi-language sites.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Automatic Image Optimization$q$, $q$A pipeline that handles resizing, cropping and format conversion automatically.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Extensive Plugin and Theme Marketplace$q$, $q$A wide range of free and premium plugins and themes for blogs, portfolios and documentation sites.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Completely free, open source core under the permissive MIT License$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$No database to install, secure or migrate; content is portable plain-text files$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Native Git version control for all content and configuration$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Modern, fast admin interface with real-time collaborative editing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Smaller plugin and theme ecosystem than WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Flat-file architecture can be less efficient than a database for very large sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Premium themes and advanced search require additional paid purchases$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Requires more technical comfort with Git, the CLI and YAML than typical point-and-click site builders$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Is Grav free?$q$, $q$Yes, the Grav core CMS is free and open source under the MIT License.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Does Grav use a database?$q$, $q$No, Grav is a flat-file CMS that stores content as Markdown files with YAML frontmatter instead of a database.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Can I version control a Grav site with Git?$q$, $q$Yes, Grav is designed natively for Git-based workflows since all content lives as plain text files.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Who created Grav?$q$, $q$Grav was created by Andy Miller, a Joomla co-founder and founder of the theme studio RocketTheme.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Does Grav have an admin panel?$q$, $q$Yes, the Admin 2.0 single-page application dashboard provides a full graphical editing interface.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Are there premium Grav themes?$q$, $q$Yes, Trilby Media sells premium themes and plugin bundles, with individual themes starting around 50 dollars.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Developer Blogs and Documentation Sites$q$, $q$Build fast, Git-versioned technical blogs and documentation without a database.$q$, $q$Developers and technical writers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Agency Client Websites Needing Git-Based Workflows$q$, $q$Deliver client sites with version-controlled content and simple portability between servers.$q$, $q$Web development agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Lightweight Portfolio and Brochure Sites$q$, $q$Run small, fast-loading marketing or portfolio sites without database overhead.$q$, $q$Freelancers and small businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Open Source Core$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full CMS and admin panel","Grav Package Manager","Unlimited self-hosted sites"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Premium Themes$q$, $q$From around $50 per theme$q$, $q$One-time$q$, NULL, $q$["Individual premium theme","Lifetime updates","Support included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$Premium Bundles$q$, $q$Around $200$q$, $q$One-time$q$, NULL, $q$["Bundled premium themes","Documentation editor and search tools","Lifetime updates and support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Grav is an open source flat-file CMS built in PHP that stores content as Markdown files rather than in a database. It was created by Andy Miller, a Joomla co-founder and RocketTheme founder, first released in 2014 and reaching its 1.0 stable milestone in November 2015.$q$, $q$Grav has no outside investors; it is developed and commercially supported by Trilby Media LLC, which sells premium themes and plugins on top of a core CMS that remains free under the MIT License.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Grav 2.x runs on PHP 8.3+, Symfony 7 and Twig 3, storing content as Git-friendly Markdown files with YAML frontmatter, fully portable without any database migration.$q$, $q$It ships the Admin 2.0 SvelteKit-based dashboard with real-time collaborative editing, the Grav Package Manager and CLI console, built-in multi-language support, automatic image optimization, and even a Model Context Protocol server for AI agent access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbbd32cd-6120-4478-b00a-9de654f9e59e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Grav core CMS, admin panel and package manager are completely free to download, self-host and use on unlimited sites under the MIT License.$q$, $q$Trilby Media generates revenue through optional premium themes, such as the Helios theme around 50 dollars, and bundled packages around 200 dollars that include lifetime updates and support.$q$]::text[], 2);
